1	/* Tier-2 C-level fixture: 16x16x16 GEMM split across all three phases.
2	 *
3	 *   QEMU 1: init_matrices -- fills A and B with deterministic patterns.
4	 *   vsim:   matmul_kernel -- pure C = A * B, no syscalls (phase-2 rule).
5	 *   QEMU 2: prints C row-by-row via printf, then re-derives the expected
6	 *           value of every C[i][j] and compares. Mismatch -> _exit(1).
7	 *
8	 * Cross-phase memory survival
9	 *   Matrices sit in .bss. The "no redundant ELF reload" rule (vsim
10	 *   skips load_elf and QEMU 2 drops -kernel when --shared-mem-path is
11	 *   set) keeps phase-1 .bss writes intact through the shared
12	 *   memory-backend-file.
13	 */
14	#include "runtime/rt_c_helpers.h"
15	
16	#include <stdint.h>
17	#include <stdio.h>
18	
19	#define N 16
20	
21	static int32_t A[N * N];
22	static int32_t B[N * N];
23	static int32_t C[N * N];
24	
25	#define AT(M, i, j) ((M)[(i) *N + (j)])
26	
27	static void init_matrices(void)
28	{
29	  for (int i = 0; i < N; i++) {
30	    for (int j = 0; j < N; j++) {
31	      AT(A, i, j) = (int32_t) ((i + j) % 7);
32	      AT(B, i, j) = (int32_t) ((i * 3 + j) % 5);
33	    }
34	  }
35	}
36	
37	static void matmul_kernel(void)
38	{
39	  for (int i = 0; i < N; i++) {
40	    for (int j = 0; j < N; j++) {
41	      int32_t s = 0;
42	      for (int k = 0; k < N; k++) {
43	        s += AT(A, i, k) * AT(B, k, j);
44	      }
45	      AT(C, i, j) = s;
46	    }
47	  }
48	}
49	
50	/* Independent recomputation in QEMU2 -- catches any kernel error. */
51	static int verify(void)
52	{
53	  for (int i = 0; i < N; i++) {
54	    for (int j = 0; j < N; j++) {
55	      int32_t s = 0;
56	      for (int k = 0; k < N; k++) {
57	        s += AT(A, i, k) * AT(B, k, j);
58	      }
59	      if (AT(C, i, j) != s)
60	        return 0;
61	    }
62	  }
63	  return 1;
64	}
65	
66	int main(void)
67	{
68	  /* Phase 1 (QEMU 1): seed inputs. */
69	  init_matrices();
70	
71	  enter_vsim();
72	
73	  /* Phase 2 (vsim): GEMM kernel only. No syscalls. */
74	  matmul_kernel();
75	
76	  exit_vsim();
77	
78	  /* Phase 3 (QEMU 2): print + verify. */
79	  printf("rt_c_matmul: C[16][16]=\n");
80	  for (int i = 0; i < N; i++) {
81	    for (int j = 0; j < N; j++)
82	      printf("%4d ", (int) AT(C, i, j));
83	    printf("\n");
84	  }
85	
86	  if (!verify()) {
87	    printf("rt_c_matmul: FAIL\n");
88	    fflush(stdout);
89	    return 1;
90	  }
91	  printf("rt_c_matmul: PASS\n");
92	  fflush(stdout);
93	  return 0;
94	}
