1	/* Tier-2 C-level fixture: 16x16x16 GEMM via RVV intrinsics, split across
2	 * the three handoff phases.
3	 *
4	 *   QEMU 1: init_matrices -- RVV vid.v + vadd.vx + vrem.vx fills A and B.
5	 *           V instructions retire just before the entry drain, exercising
6	 *           the plugin's HandoffSite translation-time PC capture (the
7	 *           old qemu_plugin_read_register("pc") path lagged for V).
8	 *   vsim:   vmatmul_kernel -- RVV outer-product GEMM (vle32 + vmacc.vx +
9	 *           vse32). V instructions also straddle the exit drain.
10	 *   QEMU 2: scalar_matmul_verify -- pure C reference recomputation, then
11	 *           cell-by-cell compare against vsim's C. Mismatch -> PASS=0.
12	 *
13	 * RVV shape
14	 *   VLEN=512, e32, LMUL=1 -> vlmax = 16 elements per V reg, exactly one
15	 *   row of a 16-wide matrix. The kernel runs N outer iterations (one per
16	 *   row of A), each accumulating into a single V register seeded to zero
17	 *   and storing it back as one row of C. No mask register, no tail policy
18	 *   subtlety: the vl set by vsetvli equals N for every iteration.
19	 *
20	 * Cross-phase memory survival (same convention as rt_c_matmul.c)
21	 *   Matrices sit in .bss. The "no redundant ELF reload" rule (vsim
22	 *   skips load_elf and QEMU 2 drops -kernel when --shared-mem-path is
23	 *   set) keeps phase-1 .bss writes intact through the shared
24	 *   memory-backend-file.
25	 */
26	#include "runtime/rt_c_helpers.h"
27	
28	#include <riscv_vector.h>
29	#include <stdint.h>
30	#include <stdio.h>
31	
32	#define N 16
33	
34	static int32_t A[N * N];
35	static int32_t B[N * N];
36	static int32_t C[N * N];
37	
38	#define AT(M, i, j) ((M)[(i) *N + (j)])
39	
40	/* Vectorized init: one V register holds [0, 1, ..., N-1], reused across
41	 * rows. Per row i: A[i][:] = (vidx + i)   % 7, B[i][:] = (vidx + 3i) % 5.
42	 * vid.v writes unsigned lane indices; reinterpret to signed so the rest of
43	 * the math (and the int32_t* matrix pointers) stay in i32 land. */
44	static void init_matrices(void)
45	{
46	  size_t           vl     = __riscv_vsetvl_e32m1((size_t) N);
47	  const vuint32m1_t vidx_u = __riscv_vid_v_u32m1(vl);
48	  const vint32m1_t  vidx   = __riscv_vreinterpret_v_u32m1_i32m1(vidx_u);
49	
50	  for (int i = 0; i < N; i++) {
51	    vint32m1_t va = __riscv_vadd_vx_i32m1(vidx, i, vl);
52	    va            = __riscv_vrem_vx_i32m1(va, 7, vl);
53	    __riscv_vse32_v_i32m1(&AT(A, i, 0), va, vl);
54	
55	    vint32m1_t vb = __riscv_vadd_vx_i32m1(vidx, i * 3, vl);
56	    vb            = __riscv_vrem_vx_i32m1(vb, 5, vl);
57	    __riscv_vse32_v_i32m1(&AT(B, i, 0), vb, vl);
58	  }
59	}
60	
61	/* Outer-product RVV GEMM: for each row i of C, accumulate
62	 *   C[i][:] += A[i][k] * B[k][:]
63	 * using a single V register per row. */
64	static void vmatmul_kernel(void)
65	{
66	  for (int i = 0; i < N; i++) {
67	    size_t     vl   = __riscv_vsetvl_e32m1((size_t) N);
68	    vint32m1_t vacc = __riscv_vmv_v_x_i32m1(0, vl);
69	    for (int k = 0; k < N; k++) {
70	      const int32_t  a_ik = AT(A, i, k);
71	      const vint32m1_t vb_k =
72	        __riscv_vle32_v_i32m1(&AT(B, k, 0), vl);
73	      vacc = __riscv_vmacc_vx_i32m1(vacc, a_ik, vb_k, vl);
74	    }
75	    __riscv_vse32_v_i32m1(&AT(C, i, 0), vacc, vl);
76	  }
77	}
78	
79	/* Pure scalar reference, independent of the RVV kernel above. */
80	static int scalar_matmul_verify(void)
81	{
82	  for (int i = 0; i < N; i++) {
83	    for (int j = 0; j < N; j++) {
84	      int32_t s = 0;
85	      for (int k = 0; k < N; k++)
86	        s += AT(A, i, k) * AT(B, k, j);
87	      if (AT(C, i, j) != s)
88	        return 0;
89	    }
90	  }
91	  return 1;
92	}
93	
94	int main(void)
95	{
96	  /* Phase 1 (QEMU 1): seed inputs only. */
97	  init_matrices();
98	
99	  enter_vsim();
100	
101	  /* Phase 2 (vsim): RVV kernel only. No I/O permitted. */
102	  vmatmul_kernel();
103	
104	  exit_vsim();
105	
106	  /* Phase 3 (QEMU 2): scalar reference compare. */
107	  if (!scalar_matmul_verify()) {
108	    printf("rt_c_v_matmul: FAIL\n");
109	    fflush(stdout);
110	    return 1;
111	  }
112	  printf("rt_c_v_matmul: PASS\n");
113	  fflush(stdout);
114	  return 0;
115	}
