1	/* Tier-2 fixture: regression for the "no redundant ELF reload" rule.
2	 *
3	 *   QEMU 1: seeds `static uint32_t buf[N]` in .bss with a deterministic
4	 *           pattern.
5	 *   vsim:   crosses the enter_vsim/exit_vsim boundary without touching buf.
6	 *   QEMU 2: reads buf back and verifies the pattern.
7	 *
8	 * Without the rule, vsim's elf_loader and QEMU 2's `-kernel` both
9	 * `std::fill_n(memsz - filesz, 0)` over the PT_LOAD covering .bss,
10	 * wiping the phase-1 seed. With the rule, the shared mmap retains the
11	 * bytes across phases 1->2->3 and the verification passes.
12	 *
13	 * Memory layout: buf lives in .bss inside the shared mmap (allocated by
14	 * the linker right after .data; see rt_c.ld). Stack is at 0x00700000. */
15	
16	#include "runtime/rt_c_helpers.h"
17	
18	#include <stdint.h>
19	#include <stdio.h>
20	
21	#define N 64
22	
23	static uint32_t buf[N];
24	
25	static uint32_t pattern(int i)
26	{
27	  return (uint32_t)((uint32_t) i * 0xDEADBEEFu + 0x12345678u);
28	}
29	
30	int main(void)
31	{
32	  for (int i = 0; i < N; i++)
33	    buf[i] = pattern(i);
34	
35	  enter_vsim();
36	  /* Phase 2: no-op. The whole point is to verify that crossing the
37	   * vsim boundary does not zero .bss. */
38	  exit_vsim();
39	
40	  for (int i = 0; i < N; i++) {
41	    const uint32_t exp = pattern(i);
42	    if (buf[i] != exp) {
43	      printf("rt_c_static_buf: FAIL i=%d exp=0x%08x got=0x%08x\n",
44	             i, exp, buf[i]);
45	      fflush(stdout);
46	      return 1;
47	    }
48	  }
49	  printf("rt_c_static_buf: PASS\n");
50	  fflush(stdout);
51	  return 0;
52	}
