1	/*
2	 * F14 fixture: small C program with NO csrwi 0x7C0,* trigger anywhere.
3	 * Exits naturally via crt0 -> _exit (libgloss_vh semihosting EXIT).
4	 *
5	 * QEMU sees the semihosting EXIT and runs its atexit chain; the
6	 * hybrid_handoff plugin's `drain_at_exit=1` callback drains state and
7	 * _exit(200) so ./hsim estimate --icount 0 can read minstret as N_total.
8	 *
9	 * Loop is sized so the BBV profile pass at slice=1000 produces enough
10	 * rows for SimPoint --max-k 2 (>= 2 rows; we want >= 10 for safety).
11	 */
12	#include <stdio.h>
13	
14	int main(void) {
15	    long acc = 0;
16	    for (long i = 0; i < 2000; i++) {
17	        acc += i * 3 + 7;
18	    }
19	    printf("no_trigger_exit acc=%ld\n", acc);
20	    return 0;
21	}
